INSERT INTO `pw_comments` VALUES (1,1,'Một người bình luận WordPress','wapuu@wordpress.example','https://vi.wordpress.org/','','2026-04-30 10:07:01','2026-04-30 10:07:01','Xin chào, đây là một bình luận.\nĐể bắt đầu kiểm duyệt, chỉnh sửa và xóa nhận xét, vui lòng truy cập màn hình Nhận xét trong trang quản trị.\nHình đại diện của người bình luận đến từ <a href=\"https://gravatar.com/\">Gravatar</a>.',0,'1','','comment',0,0),(2,51,'WooCommerce','woocommerce@noithat.local','','','2026-05-02 08:15:28','2026-05-02 08:15:28','Đơn hàng đặt qua website. Trạng thái đơn hàng đã thay đổi từ Chờ thanh toán thành Đang xử lý.',0,'1','WooCommerce','order_note',0,0),(3,52,'WooCommerce','woocommerce@noithat.local','','','2026-05-02 08:16:42','2026-05-02 08:16:42','Đơn hàng đặt qua website. Trạng thái đơn hàng đã thay đổi từ Chờ thanh toán thành Đang xử lý.',0,'1','WooCommerce','order_note',0,0);
/*!40000 ALTER TABLE `pw_comments` ENABLE KEYS */;
UNLOCK TABLES;

