INSERT INTO `pw_posts` VALUES (1,1,'2026-04-30 10:07:01','2026-04-30 10:07:01','<!-- wp:paragraph -->\n<p>Cảm ơn vì đã sử dụng WordPress. Đây là bài viết đầu tiên của bạn. Sửa hoặc xóa nó, và bắt đầu bài viết của bạn nhé!</p>\n<!-- /wp:paragraph -->','Chào tất cả mọi người!','','publish','open','open','','chao-moi-nguoi','','','2026-04-30 10:07:01','2026-04-30 10:07:01','',0,'http://noithat.local/wordpress/?p=1',0,'post','',1),(2,1,'2026-04-30 10:07:01','2026-04-30 10:07:01','<!-- wp:paragraph -->\n<p>Đây là trang mẫu. Nó khác với bài viết bởi vì nó thường cố định và hiển thị trong menu của bạn. Nhiều người bắt đầu với trang Giới thiệu nơi bạn chia sẻ thông tin cho những ai ghé thăm. Nó có thể bắt đầu như thế này:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Chào bạn! Tôi là một người bán hàng, và đây là website của tôi. Tôi sống ở Hà Nội, có một gia đình nhỏ, và tôi thấy cách sử dụng WordPress rất thú vị.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>... hoặc cái gì đó như thế này:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Công ty chúng tôi được thành lập năm 2010, và cung cấp dịch vụ chất lượng cho rất nhiều sự kiện tại khắp Việt Nam. Với văn phòng đặt tại Hà Nội, TP. Hồ Chí Minh cùng hơn 40 nhân sự, chúng tôi là nơi nhiều đối tác tin tưởng giao cho tổ chức các sự kiện lớn.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>Là một người dùng WordPress mới, bạn nên ghé thăm <a href=\"http://noithat.local/wordpress/wp-admin/\">bảng điều khiển</a> để xóa trang này và tạo trang mới cho nội dung của chính bạn. Chúc bạn vui vẻ!</p>\n<!-- /wp:paragraph -->','Trang mẫu','','publish','closed','open','','trang-mau','','','2026-04-30 10:07:01','2026-04-30 10:07:01','',0,'http://noithat.local/wordpress/?page_id=2',0,'page','',0),(3,1,'2026-04-30 10:07:01','2026-04-30 10:07:01','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Chúng tôi là ai</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Địa chỉ website là: http://noithat.local/wordpress.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Bình luận</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Khi khách truy cập để lại bình luận trên trang web, chúng tôi thu thập dữ liệu được hiển thị trong biểu mẫu bình luận và cũng là địa chỉ IP của người truy cập và chuỗi user agent của người dùng trình duyệt để giúp phát hiện bình luận rác</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Một chuỗi ẩn danh được tạo từ địa chỉ email của bạn (còn được gọi là hash) có thể được cung cấp cho dịch vụ Gravatar để xem bạn có đang sử dụng nó hay không. Chính sách bảo mật của dịch vụ Gravatar có tại đây: https://automattic.com/privacy/. Sau khi chấp nhận bình luận của bạn, ảnh tiểu sử của bạn được hiển thị công khai trong ngữ cảnh bình luận của bạn.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Thư viện</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Nếu bạn tải hình ảnh lên trang web, bạn nên tránh tải lên hình ảnh có dữ liệu vị trí được nhúng (EXIF GPS) đi kèm. Khách truy cập vào trang web có thể tải xuống và giải nén bất kỳ dữ liệu vị trí nào từ hình ảnh trên trang web.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Nếu bạn viết bình luận trong website, bạn có thể cung cấp cần nhập tên, email địa chỉ website trong cookie. Các thông tin này nhằm giúp bạn không cần nhập thông tin nhiều lần khi viết bình luận khác. Cookie này sẽ được lưu giữ trong một năm.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Nếu bạn vào trang đăng nhập, chúng tôi sẽ thiết lập một cookie tạm thời để xác định nếu trình duyệt cho phép sử dụng cookie. Cookie này không bao gồm thông tin cá nhân và sẽ được gỡ bỏ khi bạn đóng trình duyệt.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Khi bạn đăng nhập, chúng tôi sẽ thiết lập một vài cookie để lưu thông tin đăng nhập và lựa chọn hiển thị. Thông tin đăng nhập gần nhất lưu trong hai ngày, và lựa chọn hiển thị gần nhất lưu trong một năm. Nếu bạn chọn &quot;Nhớ tôi&quot;, thông tin đăng nhập sẽ được lưu trong hai tuần. Nếu bạn thoát tài khoản, thông tin cookie đăng nhập sẽ bị xoá.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Nếu bạn sửa hoặc xuất bản bài viết, một bản cookie bổ sung sẽ được lưu trong trình duyệt. Cookie này không chứa thông tin cá nhân và chỉ đơn giản bao gồm ID của bài viết bạn đã sửa. Nó tự động hết hạn sau 1 ngày.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Nội dung nhúng từ website khác</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Các bài viết trên trang web này có thể bao gồm nội dung được nhúng (ví dụ: video, hình ảnh, bài viết, v.v.). Nội dung được nhúng từ các trang web khác hoạt động theo cùng một cách chính xác như khi khách truy cập đã truy cập trang web khác.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Những website này có thể thu thập dữ liệu về bạn, sử dụng cookie, nhúng các trình theo dõi của bên thứ ba và giám sát tương tác của bạn với nội dung được nhúng đó, bao gồm theo dõi tương tác của bạn với nội dung được nhúng nếu bạn có tài khoản và đã đăng nhập vào trang web đó.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Chúng tôi chia sẻ dữ liệu của bạn với ai</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Nếu bạn yêu cầu đặt lại mật khẩu, địa chỉ IP của bạn sẽ được bao gồm trong email đặt lại.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Dữ liệu của bạn tồn tại bao lâu</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Nếu bạn để lại bình luận, bình luận và siêu dữ liệu của nó sẽ được giữ lại vô thời hạn. Điều này là để chúng tôi có thể tự động nhận ra và chấp nhận bất kỳ bình luận nào thay vì giữ chúng trong khu vực đợi kiểm duyệt.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Đối với người dùng đăng ký trên trang web của chúng tôi (nếu có), chúng tôi cũng lưu trữ thông tin cá nhân mà họ cung cấp trong hồ sơ người dùng của họ. Tất cả người dùng có thể xem, chỉnh sửa hoặc xóa thông tin cá nhân của họ bất kỳ lúc nào (ngoại trừ họ không thể thay đổi tên người dùng của họ). Quản trị viên trang web cũng có thể xem và chỉnh sửa thông tin đó.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Các quyền nào của bạn với dữ liệu của mình</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Nếu bạn có tài khoản trên trang web này hoặc đã để lại nhận xét, bạn có thể yêu cầu nhận tệp xuất dữ liệu cá nhân mà chúng tôi lưu giữ về bạn, bao gồm mọi dữ liệu bạn đã cung cấp cho chúng tôi. Bạn cũng có thể yêu cầu chúng tôi xóa mọi dữ liệu cá nhân mà chúng tôi lưu giữ về bạn. Điều này không bao gồm bất kỳ dữ liệu nào chúng tôi có nghĩa vụ giữ cho các mục đích hành chính, pháp lý hoặc bảo mật.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Dữ liệu của bạn được gửi đến đâu</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Văn bản được đề xuất: </strong>Các bình luận của khách (không phải là thành viên) có thể được kiểm tra thông qua dịch vụ tự động phát hiện bình luận rác.</p>\n<!-- /wp:paragraph -->\n','Chính sách bảo mật','','draft','closed','open','','chinh-sach-bao-mat','','','2026-04-30 10:07:01','2026-04-30 10:07:01','',0,'http://noithat.local/wordpress/?page_id=3',0,'page','',0),(4,0,'2026-04-30 10:07:02','2026-04-30 10:07:02','<!-- wp:page-list /-->','Điều hướng','','publish','closed','closed','','navigation','','','2026-04-30 10:07:02','2026-04-30 10:07:02','',0,'http://noithat.local/wordpress/2026/04/30/navigation/',0,'wp_navigation','',0),(5,1,'2026-04-30 10:08:19','0000-00-00 00:00:00','','Lưu nháp tự động','','auto-draft','open','open','','','','','2026-04-30 10:08:19','0000-00-00 00:00:00','',0,'http://noithat.local/wordpress/?p=5',0,'post','',0),(6,1,'2026-04-30 10:20:19','2026-04-30 10:20:19','','woocommerce-placeholder','','inherit','open','closed','','woocommerce-placeholder','','','2026-04-30 10:20:19','2026-04-30 10:20:19','',0,'http://noithat.local/wp-content/uploads/2026/04/woocommerce-placeholder.webp',0,'attachment','image/webp',0),(7,1,'2026-04-30 10:20:19','2026-04-30 10:20:19','','Cửa hàng','','publish','closed','closed','','cua-hang','','','2026-04-30 10:20:19','2026-04-30 10:20:19','',0,'http://noithat.local/index.php/cua-hang/',0,'page','',0),(8,1,'2026-04-30 10:20:19','2026-04-30 10:20:19','<!-- wp:shortcode -->[woocommerce_cart]<!-- /wp:shortcode -->','Giỏ hàng','','publish','closed','closed','','gio-hang','','','2026-05-02 04:40:22','2026-05-02 04:40:22','',0,'http://noithat.local/index.php/gio-hang/',0,'page','',0),(9,1,'2026-04-30 10:20:19','2026-04-30 10:20:19','<!-- wp:shortcode -->[woocommerce_checkout]<!-- /wp:shortcode -->','Thanh toán','','publish','closed','closed','','thanh-toan','','','2026-04-30 10:20:19','2026-04-30 10:20:19','',0,'http://noithat.local/index.php/thanh-toan/',0,'page','',0),(10,1,'2026-04-30 10:20:19','2026-04-30 10:20:19','<!-- wp:shortcode -->[woocommerce_my_account]<!-- /wp:shortcode -->','Tài khoản','','publish','closed','closed','','tai-khoan','','','2026-04-30 10:20:19','2026-04-30 10:20:19','',0,'http://noithat.local/index.php/tai-khoan/',0,'page','',0),(11,1,'2026-04-30 10:20:19','0000-00-00 00:00:00','<!-- wp:paragraph -->\n<p><b>This is a sample page.</b></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Overview</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our refund and returns policy lasts 30 days. If 30 days have passed since your purchase, we can’t offer you a full refund or exchange.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>To be eligible for a return, your item must be unused and in the same condition that you received it. It must also be in the original packaging.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Several types of goods are exempt from being returned. Perishable goods such as food, flowers, newspapers or magazines cannot be returned. We also do not accept products that are intimate or sanitary goods, hazardous materials, or flammable liquids or gases.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Additional non-returnable items:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Gift cards</li>\n<li>Downloadable software products</li>\n<li>Some health and personal care items</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To complete your return, we require a receipt or proof of purchase.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Please do not send your purchase back to the manufacturer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>There are certain situations where only partial refunds are granted:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Book with obvious signs of use</li>\n<li>CD, DVD, VHS tape, software, video game, cassette tape, or vinyl record that has been opened.</li>\n<li>Any item not in its original condition, is damaged or missing parts for reasons not due to our error.</li>\n<li>Any item that is returned more than 30 days after delivery</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Refunds</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Once your return is received and inspected, we will send you an email to notify you that we have received your returned item. We will also notify you of the approval or rejection of your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are approved, then your refund will be processed, and a credit will automatically be applied to your credit card or original method of payment, within a certain amount of days.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Late or missing refunds</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you haven’t received a refund yet, first check your bank account again.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Then contact your credit card company, it may take some time before your refund is officially posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Next contact your bank. There is often some processing time before a refund is posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you’ve done all of this and you still have not received your refund yet, please contact us at {email address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sale items</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Only regular priced items may be refunded. Sale items cannot be refunded.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Exchanges</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We only replace items if they are defective or damaged. If you need to exchange it for the same item, send us an email at {email address} and send your item to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Gifts</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If the item was marked as a gift when purchased and shipped directly to you, you’ll receive a gift credit for the value of your return. Once the returned item is received, a gift certificate will be mailed to you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If the item wasn’t marked as a gift when purchased, or the gift giver had the order shipped to themselves to give to you later, we will send a refund to the gift giver and they will find out about your return.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Shipping returns</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>To return your product, you should mail your product to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You will be responsible for paying for your own shipping costs for returning your item. Shipping costs are non-refundable. If you receive a refund, the cost of return shipping will be deducted from your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Depending on where you live, the time it may take for your exchanged product to reach you may vary.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are returning more expensive items, you may consider using a trackable shipping service or purchasing shipping insurance. We don’t guarantee that we will receive your returned item.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Need help?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Contact us at {email} for questions related to refunds and returns.</p>\n<!-- /wp:paragraph -->','Chính sách đổi trả hàng','','draft','closed','closed','','hoan-tien-tra-hang','','','2026-04-30 10:20:19','0000-00-00 00:00:00','',0,'http://noithat.local/?page_id=11',0,'page','',0),(12,1,'2026-04-30 10:22:18','2026-04-30 10:22:18','<!-- wp:woocommerce/cart -->\n<div class=\"wp-block-woocommerce-cart alignwide is-loading\"><!-- wp:woocommerce/filled-cart-block -->\n<div class=\"wp-block-woocommerce-filled-cart-block\"><!-- wp:woocommerce/cart-items-block -->\n<div class=\"wp-block-woocommerce-cart-items-block\"><!-- wp:woocommerce/cart-line-items-block -->\n<div class=\"wp-block-woocommerce-cart-line-items-block\"></div>\n<!-- /wp:woocommerce/cart-line-items-block -->\n\n<!-- wp:woocommerce/product-collection {\"queryId\":0,\"query\":{\"perPage\":3,\"pages\":1,\"offset\":0,\"postType\":\"product\",\"order\":\"asc\",\"orderBy\":\"title\",\"search\":\"\",\"exclude\":[],\"inherit\":false,\"taxQuery\":{},\"isProductCollectionBlock\":true,\"featured\":false,\"woocommerceOnSale\":false,\"woocommerceStockStatus\":[\"instock\",\"outofstock\",\"onbackorder\"],\"woocommerceAttributes\":[],\"woocommerceHandPickedProducts\":[],\"filterable\":false,\"relatedBy\":{\"categories\":true,\"tags\":true}},\"tagName\":\"div\",\"displayLayout\":{\"type\":\"flex\",\"columns\":3,\"shrinkColumns\":true},\"dimensions\":{\"widthType\":\"fill\"},\"collection\":\"woocommerce/product-collection/cross-sells\",\"hideControls\":[\"filterable\"],\"queryContextIncludes\":[\"collection\"],\"__privatePreviewState\":{\"isPreview\":true,\"previewMessage\":\"Actual products will vary depending on the page being viewed.\"}} -->\n<div class=\"wp-block-woocommerce-product-collection\"><!-- wp:heading {\"textAlign\":\"left\",\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"1rem\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-left\" style=\"margin-bottom:1rem\">Bạn có thể thích&hellip;</h2>\n\n<!-- /wp:heading -->\n\n<!-- wp:woocommerce/product-template -->\n<!-- wp:woocommerce/product-image {\"showSaleBadge\":false,\"imageSizing\":\"thumbnail\",\"isDescendentOfQueryLoop\":true} -->\n<!-- wp:woocommerce/product-sale-badge {\"align\":\"right\"} /-->\n<!-- /wp:woocommerce/product-image -->\n\n<!-- wp:post-title {\"textAlign\":\"center\",\"isLink\":true,\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"0.75rem\",\"top\":\"0\"}},\"typography\":{\"lineHeight\":\"1.4\"}},\"fontSize\":\"medium\",\"__woocommerceNamespace\":\"woocommerce/product-collection/product-title\"} /-->\n\n<!-- wp:woocommerce/product-price {\"isDescendentOfQueryLoop\":true,\"textAlign\":\"center\",\"fontSize\":\"small\"} /-->\n\n<!-- wp:woocommerce/product-button {\"textAlign\":\"center\",\"isDescendentOfQueryLoop\":true,\"fontSize\":\"small\"} /-->\n<!-- /wp:woocommerce/product-template --></div>\n<!-- /wp:woocommerce/product-collection --></div>\n\n<!-- /wp:woocommerce/cart-items-block -->\n\n<!-- wp:woocommerce/cart-totals-block -->\n<div class=\"wp-block-woocommerce-cart-totals-block\"><!-- wp:woocommerce/cart-order-summary-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-block\"><!-- wp:woocommerce/cart-order-summary-heading-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-heading-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-heading-block -->\n\n<!-- wp:woocommerce/cart-order-summary-coupon-form-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-coupon-form-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-coupon-form-block -->\n\n<!-- wp:woocommerce/cart-order-summary-subtotal-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-subtotal-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-subtotal-block -->\n\n<!-- wp:woocommerce/cart-order-summary-fee-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-fee-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-fee-block -->\n\n<!-- wp:woocommerce/cart-order-summary-discount-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-discount-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-discount-block -->\n\n<!-- wp:woocommerce/cart-order-summary-shipping-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-shipping-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-shipping-block -->\n\n<!-- wp:woocommerce/cart-order-summary-taxes-block -->\n<div class=\"wp-block-woocommerce-cart-order-summary-taxes-block\"></div>\n<!-- /wp:woocommerce/cart-order-summary-taxes-block --></div>\n<!-- /wp:woocommerce/cart-order-summary-block -->\n\n<!-- wp:woocommerce/cart-express-payment-block -->\n<div class=\"wp-block-woocommerce-cart-express-payment-block\"></div>\n<!-- /wp:woocommerce/cart-express-payment-block -->\n\n<!-- wp:woocommerce/proceed-to-checkout-block -->\n<div class=\"wp-block-woocommerce-proceed-to-checkout-block\"></div>\n<!-- /wp:woocommerce/proceed-to-checkout-block -->\n\n<!-- wp:woocommerce/cart-accepted-payment-methods-block -->\n<div class=\"wp-block-woocommerce-cart-accepted-payment-methods-block\"></div>\n<!-- /wp:woocommerce/cart-accepted-payment-methods-block --></div>\n<!-- /wp:woocommerce/cart-totals-block --></div>\n<!-- /wp:woocommerce/filled-cart-block -->\n\n<!-- wp:woocommerce/empty-cart-block -->\n<div class=\"wp-block-woocommerce-empty-cart-block\"><!-- wp:heading {\"textAlign\":\"center\",\"className\":\"with-empty-cart-icon wc-block-cart__empty-cart__title\"} -->\n<h2 class=\"wp-block-heading has-text-align-center with-empty-cart-icon wc-block-cart__empty-cart__title\">Giỏ hàng hiện tại chưa có sản phẩm nào!</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-dots\"} -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Mới trong cửa hàng</h2>\n<!-- /wp:heading -->\n\n<!-- wp:woocommerce/product-new {\"columns\":4,\"rows\":1} /--></div>\n<!-- /wp:woocommerce/empty-cart-block --></div>\n<!-- /wp:woocommerce/cart -->','Giỏ hàng','','inherit','closed','closed','','8-revision-v1','','','2026-04-30 10:22:18','2026-04-30 10:22:18','',8,'http://noithat.local/?p=12',0,'revision','',0),(13,1,'2026-04-30 11:09:34','2026-04-30 11:09:34','','Liên Hệ','','publish','closed','closed','','lien-he','','','2026-04-30 11:09:35','2026-04-30 11:09:35','',0,'http://noithat.local/?page_id=13',0,'page','',0),(14,1,'2026-04-30 11:09:34','2026-04-30 11:09:34','','Liên Hệ','','inherit','closed','closed','','13-revision-v1','','','2026-04-30 11:09:34','2026-04-30 11:09:34','',13,'http://noithat.local/?p=14',0,'revision','',0),(15,1,'2026-04-30 11:12:24','0000-00-00 00:00:00',' ','','','draft','closed','closed','','','','','2026-04-30 11:12:24','0000-00-00 00:00:00','',0,'http://noithat.local/?p=15',1,'nav_menu_item','',0),(18,1,'2026-05-02 02:46:10','0000-00-00 00:00:00',' ','','','draft','closed','closed','','','','','2026-05-02 02:46:10','0000-00-00 00:00:00','',0,'http://noithat.local/?p=18',1,'nav_menu_item','',0),(22,1,'2026-05-02 08:52:55','2026-05-02 02:55:46',' ','','','publish','closed','closed','','22','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=22',6,'nav_menu_item','',0),(23,1,'2026-05-02 03:02:20','2026-05-02 03:02:20','','Trang chủ','','publish','closed','closed','','trang-chu','','','2026-05-02 03:02:21','2026-05-02 03:02:21','',0,'http://noithat.local/?page_id=23',0,'page','',0),(24,1,'2026-05-02 03:02:20','2026-05-02 03:02:20','','Trang chủ','','inherit','closed','closed','','23-revision-v1','','','2026-05-02 03:02:20','2026-05-02 03:02:20','',23,'http://noithat.local/?p=24',0,'revision','',0),(25,1,'2026-05-02 08:52:55','2026-05-02 03:03:07',' ','','','publish','closed','closed','','25','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=25',1,'nav_menu_item','',0),(26,1,'2026-05-02 03:51:52','2026-05-02 03:51:52','','mẫu bàn ăn đẹp','mẫu bàn ăn đẹp','inherit','open','closed','','mau-ban-an-dep','','','2026-05-02 03:51:52','2026-05-02 03:51:52','',0,'http://noithat.local/wp-content/uploads/2026/05/ban-an-bach-ma-copy-1.jpg',0,'attachment','image/jpeg',0),(27,1,'2026-05-02 03:52:30','2026-05-02 03:52:30','','2021_Januari_095-copy-scaled','','inherit','open','closed','','2021_januari_095-copy-scaled','','','2026-05-02 03:52:30','2026-05-02 03:52:30','',0,'http://noithat.local/wp-content/uploads/2026/05/2021_Januari_095-copy-scaled-1.jpg',0,'attachment','image/jpeg',0),(28,1,'2026-05-02 04:05:54','2026-05-02 04:05:54','Giường gỗ MFC dày 18mm, có thể lật giát lên để đồ phía dưới, chiều cao thành giường 360mm, đầu giường cao 750mm.\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>Kiểu dáng</td>\r\n<td>Giường ngủ kết hợp ngăn để đồ dưới dát giường</td>\r\n</tr>\r\n<tr>\r\n<td>Kích thước</td>\r\n<td>Rộng 1234 x Sâu 2034 x Cao 360-750</td>\r\n</tr>\r\n<tr>\r\n<td>Chất liệu</td>\r\n<td>Gỗ MFC dày 18mm</td>\r\n</tr>\r\n<tr>\r\n<td>Màu sắc</td>\r\n<td>M3, M5, M6</td>\r\n</tr>\r\n<tr>\r\n<td>Bảo hành</td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\nKhác với những mẫu giường thông thường, giường gỗ GN01 là sản phẩm <a title=\"nội thất phòng ngủ\" href=\"\">nội thất phòng ngủ</a> thông minh nổi trội với tính năng “lật giát giường”. Vậy thì với tính năng đó sẽ mang đến lợi ích gì cho người dùng? Nó còn điểm đặc biệt nào khác không? Khám phá ngay dưới đây.\r\n<h2>Tính năng “lật giát giường” tăng trải nghiệm, tăng thoải mái</h2>\r\nGN01 có phải là một chiếc giường ngủ bình thường. Câu trả lời là “không”, nó được tạo ra bởi sự khác biệt cao cấp hơn, tinh tế hơn. Vì vậy đem đến nhiều tính năng tiện nghi hơn cho người dùng.\r\n\r\nChúng ta có suy nghĩ rằng giường ngủ chỉ có thể dùng để thư giãn và nghỉ ngơi, GN01 mang đến cho bạn một góc độ khác hơn. Tại sao bạn không thử tận dụng giường ngủ làm nơi bảo quản đồ dùng cá nhân như vali; quần áo chẳng hạn?','Giường ngủ GN01','','publish','open','closed','','giuong-ngu-gn01','','','2026-05-02 04:06:58','2026-05-02 04:06:58','',0,'http://noithat.local/?post_type=product&#038;p=28',0,'product','',0),(29,1,'2026-05-02 04:05:32','2026-05-02 04:05:32','','3636-giuong-ngu-gn01-1','','inherit','open','closed','','3636-giuong-ngu-gn01-1','','','2026-05-02 04:05:32','2026-05-02 04:05:32','',28,'http://noithat.local/wp-content/uploads/2026/05/3636-giuong-ngu-gn01-1.jpg',0,'attachment','image/jpeg',0),(30,1,'2026-05-02 04:08:53','2026-05-02 04:08:53','Bộ phòng ngủ 308 cao cấp màu vân gỗ trầm và trắng, kết hợp laminate\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>Kiểu dáng</td>\r\n<td>Bộ phòng ngủ gồm giường ngủ, tủ áo, táp đầu giường, bàn phấn</td>\r\n</tr>\r\n<tr>\r\n<td>Kích thước</td>\r\n<td><strong>Giường GN308:</strong> Rộng 2000 x Sâu 2236 x Cao 1000 mm\r\n<strong>Táp đầu giường TAP308:</strong> Rộng 500 x Sâu 420 x Cao 450 mm\r\n<strong>Tủ áo TA308: </strong>Rộng 1600 x Sâu 550 x Cao 2000 mm\r\n<strong>Bàn phấn BP307:</strong> Rộng 800 x Sâu 400 x Cao 1550 mm\r\nDung sai kích thước: ± 5 - 10 mm</td>\r\n</tr>\r\n<tr>\r\n<td>Chất liệu</td>\r\n<td>MFC</td>\r\n</tr>\r\n<tr>\r\n<td>Màu sắc</td>\r\n<td>Kết hợp màu trầm và trắng</td>\r\n</tr>\r\n<tr>\r\n<td>Bảo hành</td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>Bạn muốn xây dựng phòng ngủ thanh lịch? Nhưng chưa biết thiết kế nội thất ra sao? Mang đến giải pháp nhanh chóng cho người dùng, Hòa Phát cung cấp đến bạn nội thất tiện nghi kiến tạo sự sang trọng và đủ đầy cho <a title=\"nội thất phòng ngủ\" href=\"https://hoaphatsaigon.com/giuong-ngu\">nội thất phòng ngủ</a> gia đình. Sản phẩm hoàn thiện vẻ đẹp với bộ tứ nội thất bao gồm giường, tủ táp, tủ áo quần và bàn phấn.</div>\r\n<div>Tham khảo ngay combo sản phẩm dưới đây bạn nhé!</div>\r\n<h2>Bộ phòng ngủ mang đậm chất châu Âu</h2>\r\n<div>Không cần phải bàn cải về hai gam màu của tông gỗ và tông trắng kết hợp với nhau trong kiến trúc nội thất. Điểm chung của sản phẩm là từ giường, tủ tap, <a title=\"tủ quần áo\" href=\"https://hoaphatsaigon.com/tu-quan-ao\">tủ quần áo</a>, <a title=\"bàn phấn\" href=\"https://hoaphatsaigon.com/ban-trang-diem\">bàn phấn</a> đều ưa chuộng hai gam màu này. Sự đồng bộ về màu sắc mang lại cảm giác sang trọng và cực kỳ quyến rũ cho không gian phòng ngủ không kém cạnh bất kỳ nội thất kiến trúc nào. Có thể nói một từ thốt lên ngay khi bạn nhìn thấy sản phẩm là “sang”.</div>\r\n<h2>Chất liệu màu vân gỗ giữ trọn sự tự nhiên và ấm cúng</h2>\r\n<div>Nội thất từ gỗ công nghiệp luôn là lựa chọn hàng đầu của nội thất văn phòng. Và tất nhiên trong nội thất gia đình sử dụng sản phẩm từ MFC giúp gia chủ toát lên khí chất sang trọng và lịch lãm.\r\nBộ phòng ngủ 308 cao cấp màu vân gỗ trầm và trắng, kết hợp laminate. Mang một vẻ đẹp riêng biệt, độc đáo, giữ trọn lại sự tự nhiên mộc mạc vốn có của gỗ. Khiến không gian phòng ngủ trở nên độc đáo và gia tăng tính thẩm vừa đảm bảo yếu tố bền bì, mang đến chất lượng vượt trội. Vì vậy chúng rất thích hợp với người dùng yêu thích sự tự nhiên, đơn giản nhưng không kém phần tinh tế và sang trọng.\r\nThay vì đầu tư các mặt hàng kém chất lượng, sử dụng một vài năm sẽ xảy ra tình trạng hỏng hóc, tốn kém chi phí. Sử dụng combo bộ phòng ngủ 308 vừa giúp bạn tiết kiệm ngân sách lại vừa hạn chế tình trạng phải thay thế. Bởi chất liệu MFC không bao giờ bị lỗi mốt, mang lại giá trị vượt thời gian.</div>','Giường ngủ GN308','','publish','open','closed','','giuong-ngu-gn308','','','2026-05-02 04:09:35','2026-05-02 04:09:35','',0,'http://noithat.local/?post_type=product&#038;p=30',0,'product','',0),(31,1,'2026-05-02 04:08:42','2026-05-02 04:08:42','','3573-giuong-ngu-gn308-1','','inherit','open','closed','','3573-giuong-ngu-gn308-1','','','2026-05-02 04:08:42','2026-05-02 04:08:42','',30,'http://noithat.local/wp-content/uploads/2026/05/3573-giuong-ngu-gn308-1.jpg',0,'attachment','image/jpeg',0),(32,1,'2026-05-02 04:11:35','2026-05-02 04:11:35','<div class=\"csschitiet\">\r\n<div><strong><u>THÔNG SỐ KỸ THUẬT</u></strong></div>\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>Kiểu dáng</td>\r\n<td>Giường ngủ trẻ em</td>\r\n</tr>\r\n<tr>\r\n<td>Kích thước</td>\r\n<td><strong>GNE301:</strong> Rộng 1260 x Sâu 2060 x Cao 900\r\n<strong>TAE301:</strong> Rộng 1200 x Sâu 550 x Cao 1800\r\n<strong>BHE301:</strong> Rộng 1100 x Sâu 600 x Cao 1800\r\n<strong>TAPE301:</strong> Rộng 500 x Sâu 420 x Cao 440\r\nDung sai kích thước: ± 10 mm</td>\r\n</tr>\r\n<tr>\r\n<td>Chất liệu</td>\r\n<td>MFC phủ melamine</td>\r\n</tr>\r\n<tr>\r\n<td>Màu sắc</td>\r\n<td>Nhiều màu</td>\r\n</tr>\r\n<tr>\r\n<td>Bảo hành</td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div><strong>Mô tả</strong>: Bộ giường tủ phòng ngủ cho trẻ em sử dụng gỗ công nghiệp phủ Melamine cao cấp. Giường có hộc để đồ nhằm tăng không gian lưu trữ đồ cho người sử dụng.</div>\r\n<div>\r\n\r\nCuộc sống ngày nay thay đổi liên tục khiến người ta luôn hướng về cái mới mẻ và hiện đại. Để đáp ứng nhu cầu đó, không ít mẫu nội thất phòng ngủ hiện đại được ra đời. Những vật dụng đó mang một phần cuộc sống ngày nay vào phòng ngủ của bạn. Như thiết kế đầy ấn tượng của chiếc giường ngủ GNE301 dành cho trẻ em với thiết kế hộp kín chân.\r\n\r\nKhông đi theo lối mòn của thiết kế truyền thống, giường ngủ GNE301 hộp kín chân gây ấn tượng bởi sự đơn giản, tối lược các chi tiết thành phong cách hiện đại, trẻ trung. Thuộc dòng giường hộp tạo hình vuông vắn, là biểu tượng cho sự bền vững, chắc chắn, đảm bảo hạnh phúc gia đình.\r\n\r\nKhung giường được tạo hình chữ nhật mạnh mẽ với các đường thẳng thanh thoát. Các góc cạnh của giường được làm tù lại hạn chế những tổn thương khi va chạm, đặc biệt là đối với trẻ nhỏ. Mặt giường được thiết kế theo kiểu giường truyền thống là sự ghép nối của nhiều thanh gỗ ngang, thuận tiện cho việc lau chùi. Thành giường thiết kế thẳng và cao, cho người dùng tựa lưng nghỉ ngơi thoải mái. Giữa mặt giường và thành giường có một khoảng cách nhỏ tạo sự thông thoáng, mát mẻ. Trên các cạnh giường và thành giường có các đường chạm chìm nổi tinh tế, ấn tượng. Giường không chân, bệt sát đất, cho người sử dụng dễ dàng di chuyển lên xuống.\r\n\r\nChất lượng của sản phẩm được thể hiện rõ nhất là qua chất liệu cấu thành. Với việc sử dụng gỗ công nghiệp phủ Melamine cao cấp, loại chất liệu được sử dụng phổ biến trong các thiết kế nội thất gia đình hiện nay đã mang đến nhiều ưu điểm cho sản phẩm như chống ẩm tốt, có độ bền cao, dễ chịu trong quá trình vệ sinh, lau chùi. Giường có hộc để đồ nhằm tăng không gian lưu trữ đồ cho người sử dụng.\r\n\r\nSản phẩm có nhiều kích thước cho bạn lựa chọn, nên tìm vị trí đặt giường hợp phong thủy để cho gia đình bạn giấc ngủ sâu và ngon hơn, đồng thời đảm bảo được sức khỏe và tinh thần cho ngày mới.\r\n\r\n</div>\r\n</div>\r\n<div class=\"clr\"></div>\r\n<div class=\"title_cat\"></div>','Giường ngủ GNE301','','publish','open','closed','','giuong-ngu-gne301','','','2026-05-02 04:46:07','2026-05-02 04:46:07','',0,'http://noithat.local/?post_type=product&#038;p=32',0,'product','',0),(33,1,'2026-05-02 04:10:50','2026-05-02 04:10:50','','1653-giuong-ngu-gne301-1','','inherit','open','closed','','1653-giuong-ngu-gne301-1','','','2026-05-02 04:10:50','2026-05-02 04:10:50','',32,'http://noithat.local/wp-content/uploads/2026/05/1653-giuong-ngu-gne301-1.jpg',0,'attachment','image/jpeg',0),(34,1,'2026-05-02 04:15:30','2026-05-02 04:15:30','<strong>Mô tả sản phẩm:</strong>\r\n<div class=\"csschitiet\">\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td><strong>Mã sản phẩm</strong></td>\r\n<td>SF513ANK / SF513BNK</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Kiểu dáng</strong></td>\r\n<td>Ghế SF513ANK băng 3, giả da màu kem, có cơ cấu ngả\r\nGhế SF513BNK băng 3, giả da màu kem không điều chỉnh ngả được\r\n<strong>Hàng nhập khẩu</strong></td>\r\n</tr>\r\n<tr>\r\n<td><strong>Kích thước</strong></td>\r\n<td>Rộng 2660 x Sâu 970 x Cao 940 (mm)</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Chất liệu</strong></td>\r\n<td>Da PU</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Màu sắc</strong></td>\r\n<td>Kem</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Bảo hành</strong></td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>Sự đồng hành của <a title=\"ghế sofa\" href=\"https://hoaphatsaigon.com/ban-ghe-sofa\">ghế sofa</a> theo thời gian không chỉ là câu chuyện về kiểu dáng, chất liệu mà còn là về sự thoải mái và gắn kết. Sofa băng 3 chỗ ngồi SF513ANK / SF513BNK là sự đầu tư vào những khoảnh khắc ấm cúng. Thiết kế hiện đại, tinh tế dành cho những không gian sống cần sự nhẹ nhàng, dễ chịu.</div>\r\n<h3><strong>Lựa chọn linh hoạt theo phong cách sống</strong></h3>\r\n<div></div>\r\n</div>','Sofa SF513ANK | SF513BNK','','publish','open','closed','','sofa-sf513ank-sf513bnk','','','2026-05-02 04:46:41','2026-05-02 04:46:41','',0,'http://noithat.local/?post_type=product&#038;p=34',0,'product','',0),(35,1,'2026-05-02 04:14:32','2026-05-02 04:14:32','','4677-sofa-sf513ank-sf513bnk-1','','inherit','open','closed','','4677-sofa-sf513ank-sf513bnk-1','','','2026-05-02 04:14:32','2026-05-02 04:14:32','',34,'http://noithat.local/wp-content/uploads/2026/05/4677-sofa-sf513ank-sf513bnk-1.jpg',0,'attachment','image/jpeg',0),(36,1,'2026-05-02 04:15:03','2026-05-02 04:15:03','','4677-sofa-sf513ank-sf513bnk-2','','inherit','open','closed','','4677-sofa-sf513ank-sf513bnk-2','','','2026-05-02 04:15:03','2026-05-02 04:15:03','',34,'http://noithat.local/wp-content/uploads/2026/05/4677-sofa-sf513ank-sf513bnk-2.jpg',0,'attachment','image/jpeg',0),(37,1,'2026-05-02 04:17:53','2026-05-02 04:17:53','<a title=\"Ghế sofa góc SF107A\" href=\"https://hoaphatsaigon.com/3951-ghe-sf107a.html\">Ghế sofa góc SF107A</a> cao cấp, bọc da thật bề mặt tiếp xúc người sử dụng. Tựa ghế có thể điều chỉnh góc ngả nhằm giúp cho người dùng được thoải mái hơn trong quá trình sử dụng. Ghế có 2 loại kích thước: ghế 3 chỗ và 4 chỗ\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>Kiểu dáng</td>\r\n<td>Bộ ghế sofa góc chữ L bọc da gồm 3 hoặc 4 chổ ngồi</td>\r\n</tr>\r\n<tr>\r\n<td>Kích thước</td>\r\n<td><strong>SF107A-3:</strong> Rộng 2600 x Sâu 1730 x Cao 750-900 mm\r\n<strong>SF107A-4:</strong> Rộng 3330 x Sâu 1730 x Cao 750-900 mm\r\nDung sai kích thước: ± 20(mm)</td>\r\n</tr>\r\n<tr>\r\n<td>Chất liệu</td>\r\n<td>Đệm mút bọc da thật hoặc PVC</td>\r\n</tr>\r\n<tr>\r\n<td>Màu sắc</td>\r\n<td></td>\r\n</tr>\r\n<tr>\r\n<td>Bảo hành</td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>Bộ ghế sofa góc cao cấp SF107A-3 / SF107A-4 hội tụ tất cả các yếu tố tinh tế và đẳng cấp mà bất kỳ người gia chủ nào cũng hài lòng. Đây không chỉ là món đồ nội thất mà còn là một tác phẩm nghệ thuật tinh tế và đẳng cấp. Thuộc dòng <a title=\"ghế sofa da\" href=\"https://hoaphatsaigon.com/ban-ghe-sofa\">ghế sofa da</a> mang đến vẻ đẹp tự nhiên đồng thời sự thoải mái và sang trọng mà không có loại vật liệu nào khác có thể so sánh được.\r\nKhám phá ngay vẻ đẹp và những tính năng đặc biệt của sản phẩm trong bài viết dưới đây.</div>','Ghế SF107A','','publish','open','closed','','ghe-sf107a','','','2026-05-02 04:17:53','2026-05-02 04:17:53','',0,'http://noithat.local/?post_type=product&#038;p=37',0,'product','',0),(38,1,'2026-05-02 04:17:31','2026-05-02 04:17:31','','3951-ghe-sf107a-1','','inherit','open','closed','','3951-ghe-sf107a-1','','','2026-05-02 04:17:31','2026-05-02 04:17:31','',37,'http://noithat.local/wp-content/uploads/2026/05/3951-ghe-sf107a-1.jpg',0,'attachment','image/jpeg',0),(39,1,'2026-05-02 04:20:10','2026-05-02 04:20:10','<div><strong><u>THÔNG SỐ KỸ THUẬT</u></strong></div>\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>Kiểu dáng</td>\r\n<td>Sofa giường cao cấp</td>\r\n</tr>\r\n<tr>\r\n<td>Kích thước</td>\r\n<td>Rộng 2000 x Sâu 960 x Cao 860</td>\r\n</tr>\r\n<tr>\r\n<td>Chất liệu</td>\r\n<td>Đệm tựa bọc mút vải. Khung thép</td>\r\n</tr>\r\n<tr>\r\n<td>Màu sắc</td>\r\n<td>F28, F30, F31</td>\r\n</tr>\r\n<tr>\r\n<td>Bảo hành</td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>Sofa vải cao cấp có khung chịu lực bằng thép, ghế có thể ngả thành giường, có hai gối đi kèm\r\nKT giường: 2000x1200x410</div>\r\n<ul>\r\n 	<li>Sofa giường SF113A có thiết kế kiểu dáng ảnh hưởng từ phong cách retro cổ điển - đây là kiểu phong cách đang dần trở lại với sức hút ấn tượng của nó về thẩm mỹ trong thiết kế nội thất hiện nay. Màu sắc nhã nhặn tạo sự duyên dáng, lịch lãm cho không gian sống.</li>\r\n 	<li>Sofa với thiết kế đệm và tựa hình chữ nhật dài, toàn bộ được bọc vải cao cấp, chất liệu vải mềm mại đảm bảo độ nảy và độ đàn hồi tốt, không lo bám bụi, ẩm mốc, dễ vệ sinh, chất liệu này thường sử dụng cho môi trường điều hòa bởi sự tích nhiệt cao</li>\r\n 	<li>Tựa lưng ngả nhẹ nâng đỡ cột sống người ngồi vô cùng êm ái, đệm ngồi thiết kế hơi dốc xuống tạo hình thác nước giúp làm giảm áp lực lên đùi khi ngồi, tránh tình trạng tê chân, đông máu khi ngồi trong thời gian dài.</li>\r\n 	<li>Ngoài ra ghế có thể ngả thành giường, vô cùng tiện ích khi nằm ngả lưng lấy lại năng lượng nhanh chóng, tặng kèm trang trí hai gối nhỏ xinh xắn ton-sur-ton với mẫu ghế.</li>\r\n 	<li>Khung chân ghế bằng thép chịu lực với 4 chân trụ xoè vừa giúp cố định sàn nhà một cách vững chãi vừa tạo độ bền bỉ cao khi có tác động ngoại lực lên toàn bộ sản phẩm.</li>\r\n 	<li>Sản phẩm phù hợp với mọi không gian phòng khách nhà ở, văn phòng,... tôn vinh phong cách sống sang trọng, thời thượng.</li>\r\n</ul>','Sofa giường SF113A','','publish','open','closed','','sofa-giuong-sf113a','','','2026-05-02 04:20:38','2026-05-02 04:20:38','',0,'http://noithat.local/?post_type=product&#038;p=39',0,'product','',0),(40,1,'2026-05-02 04:19:51','2026-05-02 04:19:51','','2261-sofa-giuong-sf113a-1','','inherit','open','closed','','2261-sofa-giuong-sf113a-1','','','2026-05-02 04:19:51','2026-05-02 04:19:51','',39,'http://noithat.local/wp-content/uploads/2026/05/2261-sofa-giuong-sf113a-1.jpg',0,'attachment','image/jpeg',0),(41,1,'2026-05-02 04:22:37','2026-05-02 04:22:37','<h2><strong>Thông số kỹ thuật</strong></h2>\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td><strong>Mã sản phẩm</strong></td>\r\n<td>BA01-D12 / BA01-D14 / BA01-D16</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Kiểu dáng</strong></td>\r\n<td>Bàn ăn chân sắt ống tròn Ø50 tóp côn, khung đỡ mặt bàn bằng thép hộp 25x50 sơn tĩnh điện đen sần hoặc kem. Mặt bàn đá Ceramic dày 12mm\r\n<strong>Loại mặt đá đen vui lòng cộng thêm 350.000đ/bàn</strong></td>\r\n</tr>\r\n<tr>\r\n<td><strong>Kích thước</strong></td>\r\n<td>BA01-D12: Rộng 1200 x Sâu 700 x Cao 737 (mm)\r\nBA01-D14: Rộng 1400 x Sâu 800 x Cao 737 (mm)\r\nBA01-D16: Rộng 1600 x Sâu 800 x Cao 737 (mm)</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Chất liệu</strong></td>\r\n<td>Khung thép, mặt đá ceramic</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Màu sắc</strong></td>\r\n<td>Trắng hoặc đen</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Bảo hành</strong></td>\r\n<td>12 tháng</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>Trong không gian sống hiện đại, bàn ăn là nơi quây quần mỗi bữa cơm gia đình đồng thời cũng là điểm nhấn nội thất thể hiện phong cách sống của chủ nhân. Với thiết kế tinh gọn, hiện đại và đầy tính thẩm mỹ, bàn ăn BA01-D12 / BA01-D14 / BA01-D16 chính là lựa chọn lý tưởng cho những ai đang tìm kiếm sự kết hợp giữa công năng và vẻ đẹp thời thượng.</div>\r\n<h3><strong>Cấu tạo chắc chắn</strong></h3>\r\n<div>Kiểu bàn ăn BA01-D12 được thiết kế với phần chân bàn làm từ ống thép tròn Ø50 tóp côn, tạo dáng vẻ thanh mảnh nhưng chắc chắn. Lớp sơn tĩnh điện đen sần hoặc kem phủ bên ngoài giúp tăng độ bền, chống gỉ sét và giữ cho <a title=\"bàn ăn\" href=\"https://hoaphatsaigon.com/ban-ghe-phong-an\">bàn ăn</a> luôn mới đẹp sau thời gian dài sử dụng.\r\nHệ khung đỡ mặt bàn bằng thép hộp 25x50 gia công tỉ mỉ, nâng đỡ toàn bộ mặt bàn một cách vững chãi. Đây chính là chi tiết tạo nên sự khác biệt về chất lượng so với nhiều mẫu bàn thông thường trên thị trường.</div>\r\n<h3><strong>Mặt bàn đá ceramic sang trọng, đẳng cấp và dễ dàng vệ sinh</strong></h3>\r\n<div>Điểm nhấn không thể bỏ qua của BA01-D12 / BA01-D14 / BA01-D16 chính là mặt bàn đá ceramic dày 12mm, chất liệu cao cấp đang được ưa chuộng trong các thiết kế nội thất phòng ăn hiện đại. Bề mặt đá mịn chống trầy xước, chịu nhiệt tốt và không bám bẩn giúp bạn dễ dàng lau chùi sau mỗi bữa ăn. Vân đá tự nhiên được xử lý tinh xảo, mang lại vẻ đẹp sang trọng và đầy cảm hứng cho không gian bếp hoặc phòng ăn.</div>\r\n<h3><strong>Phù hợp với mọi không gian</strong></h3>\r\n<div>Nhờ kiểu dáng đơn giản, màu sắc trang nhã và kích thước vừa phải, bàn ăn BA01-D12 / BA01-D14 / BA01-D16 dễ dàng kết hợp với nhiều loại ghế ăn khác nhau, phù hợp với các không gian từ căn hộ chung cư, nhà phố đến quán ăn, quán cà phê hiện đại. Thiết kế thông minh cũng giúp tiết kiệm diện tích, tạo cảm giác thoáng đãng và thoải mái khi sử dụng.</div>','Bàn ăn BA01-D12','','publish','open','closed','','ban-an-ba01-d12','','','2026-05-02 04:23:58','2026-05-02 04:23:58','',0,'http://noithat.local/?post_type=product&#038;p=41',0,'product','',0),(42,1,'2026-05-02 04:23:12','2026-05-02 04:23:12','','4470-ban-an-ba01-d12-1','','inherit','open','closed','','4470-ban-an-ba01-d12-1','','','2026-05-02 04:23:12','2026-05-02 04:23:12','',41,'http://noithat.local/wp-content/uploads/2026/05/4470-ban-an-ba01-d12-1.jpg',0,'attachment','image/jpeg',0),(43,1,'2026-05-02 04:23:31','2026-05-02 04:23:31','','4470-ban-an-ba01-d12-2','','inherit','open','closed','','4470-ban-an-ba01-d12-2','','','2026-05-02 04:23:31','2026-05-02 04:23:31','',41,'http://noithat.local/wp-content/uploads/2026/05/4470-ban-an-ba01-d12-2.jpg',0,'attachment','image/jpeg',0),(44,1,'2026-05-02 04:26:02','2026-05-02 04:26:02','<strong>Mô tả sản phẩm:</strong>\r\n<div class=\"csschitiet\">\r\n<div>- Chất liệu: MẶT ĐÁ CERAMIC\r\n- Khung thép sắt sơn tĩnh điện\r\n- Màu sắc : Nhiều màu theo màu đá BA1\r\n(Giá bàn không ghế)\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td colspan=\"1\" rowspan=\"2\"><strong>MÃ SẢN PHẨM</strong></td>\r\n<td colspan=\"2\" rowspan=\"1\"><strong>KÍCH THƯỚC</strong></td>\r\n</tr>\r\n<tr>\r\n<td><b>Đường kính </b></td>\r\n<td><strong>Rộng</strong></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"1\" rowspan=\"3\"><strong>Mặt đá</strong></td>\r\n<td>1400</td>\r\n<td>800</td>\r\n</tr>\r\n<tr>\r\n<td>1600</td>\r\n<td>900</td>\r\n</tr>\r\n<tr>\r\n<td>1800</td>\r\n<td>900</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\nNếu bạn đang tìm kiếm những mẫu bàn ăn độc đáo khác biệt với những dòng bàn ăn thông thường. Hãy trải nghiệm ngay dòng bàn chân X kép - bàn ăn cao cấp BA18. Thiết kế không chỉ đẹp về kiểu dáng mà còn bền bỉ với chất liệu cao cấp. Tham khảo ngay sản phẩm.\r\n\r\n</div>\r\n<h2><strong>Điểm nổi bật của bàn ghế ăn chân X </strong></h2>\r\n<h3><strong>Bàn mặt đá nổi bật với đường vân độc đáo </strong></h3>\r\n<div>Có phải khi bước vào không gian bất kỳ như phòng ăn, phòng bếp, khu vực phòng chờ bạn thường ấn tượng bởi những thứ sáng bóng. BA18 sở hữu mặt bàn trơn nhẵn, chà nhám sáng bóng, vừa nhìn đã thấy ấn tượng. Nếu kết hợp cùng <a title=\"Ghế Verol A66\" href=\"https://hoaphatsaigon.com/3553-ghe-verol-a66.html\">Ghế Verol A66</a> thì không gian sẽ thêm hoàn hảo\r\nĐồng thời sự đặc sắc trong các đường vân tạo nên sức hút khó cưỡng. Điều này lý giải vì sao mà hiện nay có rất nhiều dòng bàn ăn khác nhau nhưng bàn mặt đá vân là cái tên được ưa chuộng trên thị trường.\r\nMàu sắc của mặt bàn đa dạng, nhiều màu giúp quý khách có nhiều lựa chọn hơn. Vì vậy, bàn phù hợp với mọi không gian, phong cách khác nhau. Sẽ thật hoàn hảo khi bạn kết hợp cùng những chiếc ghế ăn chân sắt tăng tính đồng điệu.</div>\r\n</div>','Bàn ăn chân X kép BA18','','publish','open','closed','','ban-an-chan-x-kep-ba18','','','2026-05-02 04:45:06','2026-05-02 04:45:06','',0,'http://noithat.local/?post_type=product&#038;p=44',0,'product','',0),(45,1,'2026-05-02 04:25:36','2026-05-02 04:25:36','','3590-ban-an-chan-x-kep-ba18-1','','inherit','open','closed','','3590-ban-an-chan-x-kep-ba18-1','','','2026-05-02 04:25:36','2026-05-02 04:25:36','',44,'http://noithat.local/wp-content/uploads/2026/05/3590-ban-an-chan-x-kep-ba18-1.jpg',0,'attachment','image/jpeg',0),(46,1,'2026-05-02 04:28:24','2026-05-02 04:28:24','<strong>Mô tả sản phẩm:</strong>\r\n<div class=\"csschitiet\"><strong>Chất liệu:</strong> Chân bàn thép cacbon sơn tĩnh điện, mặt đá phiến ceramic nhiều màu\r\n<strong>Kích thước: </strong>\r\n<ul>\r\n 	<li><strong>BA26-14:</strong> Rộng 1400 x Sâu 800 x Cao 750</li>\r\n 	<li><strong>BA26-16: </strong>Rộng 1600 x Sâu 900 x Cao 750</li>\r\n 	<li><strong>BA26-18:</strong> Rộng 1800 x Sâu 900 x Cao 750</li>\r\n</ul>\r\n<div>Để đáp ứng nhu cầu ngày càng cao của người tiêu dùng, bàn ăn BA26 mang đến phong cách trẻ trung, năng động phù hợp với xu hướng hiện đại ngày nay. Kết hợp giữa thép cacbon cùng chất liệu đá phiến sang trọng chấm phá cho không gian sự sang trọng và không gian chuyên nghiệp.</div>\r\n<h2>BA26 - thiết kế khỏe khoắn hòa quyện với sự thanh thoát</h2>\r\n<div>Gây ấn tượng với <a title=\"bàn ăn mặt đá\" href=\"https://hoaphatsaigon.com/ban-ghe-phong-an\">bàn ăn mặt đá</a> hình chữ nhật đã được xử lý các góc cạnh một cách kỹ lưỡng. Tạo điểm nhấn trong các hình thù vân độc đáo, công nghệ chà nhám mang đến sự bóng loáng và trơn nhẵn. Mặt bàn có đặc tính dễ vệ sinh, chống thấm nước chống ẩm mốc. Rất thích hợp sử dụng trong gia đình có trẻ nhỏ và người già. Đá ceramic chịu nhiệt tốt vì vậy người dùng yên tâm đặt thức ăn nóng không lo bị phai màu bàn.</div>\r\n</div>','Bàn ăn chân trái tim BA26','','publish','open','closed','','ban-an-chan-trai-tim-ba26','','','2026-05-02 04:28:24','2026-05-02 04:28:24','',0,'http://noithat.local/?post_type=product&#038;p=46',0,'product','',0),(47,1,'2026-05-02 04:27:52','2026-05-02 04:27:52','','3965-ban-an-chan-trai-tim-ba26-1','','inherit','open','closed','','3965-ban-an-chan-trai-tim-ba26-1','','','2026-05-02 04:27:52','2026-05-02 04:27:52','',46,'http://noithat.local/wp-content/uploads/2026/05/3965-ban-an-chan-trai-tim-ba26-1.jpg',0,'attachment','image/jpeg',0),(48,1,'2026-05-02 08:52:55','2026-05-02 04:35:12',' ','','','publish','closed','closed','','48','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=48',2,'nav_menu_item','',0),(49,1,'2026-05-02 08:52:55','2026-05-02 04:35:12',' ','','','publish','closed','closed','','49','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=49',3,'nav_menu_item','',0),(50,1,'2026-05-02 08:52:55','2026-05-02 04:35:12',' ','','','publish','closed','closed','','50','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=50',4,'nav_menu_item','',0),(51,0,'2026-05-02 08:15:27','2026-05-02 08:15:27','','','','draft','closed','closed','','','','','2026-05-02 08:15:27','2026-05-02 08:15:27','',0,'http://noithat.local/?post_type=shop_order_placehold&p=51',0,'shop_order_placehold','',1),(52,1,'2026-05-02 08:16:41','2026-05-02 08:16:41','','','','draft','closed','closed','','','','','2026-05-02 08:16:41','2026-05-02 08:16:41','',0,'http://noithat.local/?post_type=shop_order_placehold&p=52',0,'shop_order_placehold','',1),(53,1,'2026-05-02 08:48:42','0000-00-00 00:00:00','','Lưu nháp tự động','','auto-draft','closed','closed','','','','','2026-05-02 08:48:42','0000-00-00 00:00:00','',0,'http://noithat.local/?post_type=cong_trinh&p=53',0,'cong_trinh','',0),(54,1,'2026-05-02 08:51:31','0000-00-00 00:00:00','','','','draft','closed','closed','','','','','2026-05-02 08:51:31','0000-00-00 00:00:00','',0,'http://noithat.local/?p=54',1,'nav_menu_item','',0),(55,1,'2026-05-02 08:52:55','2026-05-02 08:52:55','','Công trình','','publish','closed','closed','','cong-trinh','','','2026-05-02 08:52:55','2026-05-02 08:52:55','',0,'http://noithat.local/?p=55',5,'nav_menu_item','',0),(56,1,'2026-05-02 09:12:36','2026-05-02 09:12:36','<!-- wp:paragraph -->\n<p>Nội thất phòng khách phòng ngủ chung cư đẹp</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:gallery {\"linkTo\":\"none\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped\"><!-- wp:image {\"id\":59,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://noithat.local/wp-content/uploads/2026/05/5021073a2539a467fd28-768x1024.jpg\" alt=\"\" class=\"wp-image-59\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery -->\n\n<!-- wp:image {\"id\":60,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://noithat.local/wp-content/uploads/2026/05/56402e4d0c4e8d10d45f-1-768x1024.jpg\" alt=\"\" class=\"wp-image-60\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:gallery {\"linkTo\":\"none\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped\"><!-- wp:image {\"id\":57,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://noithat.local/wp-content/uploads/2026/05/56402e4d0c4e8d10d45f-768x1024.jpg\" alt=\"\" class=\"wp-image-57\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery -->','Chung cư vinhome','','publish','closed','closed','','chung-cu-vinhome','','','2026-05-02 09:14:01','2026-05-02 09:14:01','',0,'http://noithat.local/?post_type=cong_trinh&#038;p=56',0,'cong_trinh','',0),(57,1,'2026-05-02 09:08:11','2026-05-02 09:08:11','','56402e4d0c4e8d10d45f','','inherit','open','closed','','56402e4d0c4e8d10d45f','','','2026-05-02 09:08:11','2026-05-02 09:08:11','',56,'http://noithat.local/wp-content/uploads/2026/05/56402e4d0c4e8d10d45f.jpg',0,'attachment','image/jpeg',0),(58,1,'2026-05-02 09:08:21','2026-05-02 09:08:21','','5021073a2539a467fd28 (1)','','inherit','open','closed','','5021073a2539a467fd28-1','','','2026-05-02 09:08:21','2026-05-02 09:08:21','',56,'http://noithat.local/wp-content/uploads/2026/05/5021073a2539a467fd28-1.jpg',0,'attachment','image/jpeg',0),(59,1,'2026-05-02 09:08:28','2026-05-02 09:08:28','','5021073a2539a467fd28','','inherit','open','closed','','5021073a2539a467fd28','','','2026-05-02 09:08:28','2026-05-02 09:08:28','',56,'http://noithat.local/wp-content/uploads/2026/05/5021073a2539a467fd28.jpg',0,'attachment','image/jpeg',0),(60,1,'2026-05-02 09:10:45','2026-05-02 09:10:45'